starterCode.css:
.grid {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  /* Add gap here */
}
.grid > div {
  background: #e0e0e0; padding: 20px;
  text-align: center; border-radius: 4px;
}

.card-grid {
  display: grid;
  grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
  gap: 8px; /* Mobile default */
  max-width: 1200px; margin: 0 auto; padding: 16px;
}

.card {
  background: #f0f0f0; padding: 30px;
  border-radius: 8px; text-align: center;
  min-height: 120px;
}

/* Add media queries for tablet (≥600px) and desktop (≥1024px) */

solution.css:
.card-grid { display: grid; grid-template-columns: repeat(auto-fit, minmax(200px, 1fr)); gap: 8px; max-width: 1200px; margin: 0 auto; padding: 16px; }
.card { background: #f0f0f0; padding: 30px; border-radius: 8px; text-align: center; min-height: 120px; }
@media (min-width: 600px) { .card-grid { gap: 16px; } }
@media (min-width: 1024px) { .card-grid { gap: 32px; } }

