solution.css:
.dashboard { display: grid; grid-template-columns: repeat(2, 1fr); gap: 20px; padding: 30px; max-width: 800px; margin: 0 auto; background: #1a1a2e; border-radius: 12px; }
.card { background: #2d2d44; color: #eee; padding: 30px; border-radius: 8px; min-height: 100px; }
